import numpy as np

def low_rank_compress(W: np.ndarray, rank: int) -> tuple:
    U, S, Vt = np.linalg.svd(W, full_matrices=False)
    return U[:, :rank], S[:rank], Vt[:rank, :]

def low_rank_reconstruct(U_r: np.ndarray, S_r: np.ndarray, Vt_r: np.ndarray) -> np.ndarray:
    return (U_r * S_r) @ Vt_r

def compression_ratio(W: np.ndarray, rank: int) -> float:
    m, n = W.shape
    original = m * n
    compressed = rank * (m + n + 1)
    return float(original / compressed)

def reconstruction_error(W: np.ndarray, rank: int) -> float:
    U_r, S_r, Vt_r = low_rank_compress(W, rank)
    W_approx = low_rank_reconstruct(U_r, S_r, Vt_r)
    return float(np.linalg.norm(W - W_approx, 'fro') / np.linalg.norm(W, 'fro'))
